var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이건 맥크레디의 빙결 능력?","JPN":"これはマクレディーの氷結能力？","ENG":"MacCready's freezing ability?","TWN":"這就是麥克蕾蒂的冰凍能力嗎？"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L3_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다는 말은…….","JPN":"ということは……","ENG":"Then that means...","TWN":"那就是說……"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"후후, 그런건가.","JPN":"ふふ、そういうことか。","ENG":"Haha, is this how this plays out?","TWN":"呵呵，原來如此。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"예상외의 전개로군. 이건 기회가 되겠어.","JPN":"予想外の展開になってきたね。いいチャンスだ。","ENG":"This is unexpected. It could be an opportunity for me.","TWN":"出乎意料的劇情發展啊，應該是個機會。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤을 돌려줘! 돌려 달란 말이야!","JPN":"アンを返して！　返してよ！","ENG":"Give Ann back! I said, give her back!","TWN":"把安妮還給我！還給我！"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>이런 개 같은 계집애가……!</color>","JPN":"<color=#ff3636>このうっとうしい小娘……！</color>","ENG":"<color=#ff3636>Why you little brat...!</color>","TWN":"<color=#ff3636>你這個死丫頭……！</color>"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>방해하지 마! 어서 놓지 못해!?</color>","JPN":"<color=#ff3636>離せ！　邪魔は許さない！</color>","ENG":"<color=#ff3636>Stop interfering! Let go of me!</color>","TWN":"<color=#ff3636>別妨礙我！還不快放手？！</color>"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"피하기에는 늦었어! 받아 칠 수밖에 없나!","JPN":"爆発を避けるにはもう遅い……！　打ち返すしかないのか……！","ENG":"It's too late! I have to deflect it!","TWN":"已經來不及躲開了！只能硬接嗎！"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만……!","JPN":"だが……！","ENG":"But…!","TWN":"但是……！"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이제 끝이네, 버넷.","JPN":"これで終わりだ、バーネット。","ENG":"It's over, Burnett.","TWN":"結束了，伯內特。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"수없이 반복되는 그 날의 기억 속에서.","JPN":"何度も繰り返されるあの日の記憶の中で。","ENG":"Within the countlessly repeating memories of that day.","TWN":"在重複了無數次的那段記憶裡。"},"stage":{"bg":"WHITE","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막에 떠오르는 것은 폭발에서 우리를 지키려던 요원님의 품과.","JPN":"最後に思い出すのは、爆発から私たちを守ろうとするエージェント様の懐と。","ENG":"The last thing I recall is the agent's arms protecting us from the explosion, and...","TWN":"最後出現的，是在爆炸中守護我們的大人的懷抱……"},"stage":{"bg":"WHITE","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"피부로 느껴지는 차가운 쇠사슬.","JPN":"肌に伝わる鎖の冷たさ。","ENG":"the cold chain against my skin.","TWN":"以及那個能切身感受到冰冷的鐵鍊。"},"stage":{"bg":"WHITE","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 속이 뒤집어질 것만 같은 멀미감이었다.","JPN":"そして吐きそうになる感覚だった。","ENG":"There was also this queasiness, enough to make one sick to the stomach.","TWN":"還有，一種眩暈的感覺。"},"stage":{"bg":"WHITE","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 다시금 눈을 떴을 때, 내가 마주하는 세계는.","JPN":"やがて気を取り戻した私の目の前に広がる世界は……","ENG":"After, when I opened my eyes, the world I saw was...","TWN":"當我再次睜開眼睛時，面對的世界……"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 끔찍한 풍경의 이곳.","JPN":"終わりのない惨状が広がるこの場所。","ENG":"this horrible landscape.","TWN":"總是慘不忍睹的這裡。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……당신은?","JPN":"……あなたは？","ENG":"...You are?","TWN":"……你是？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"미안해…….","JPN":"悪い……","ENG":"Sorry...","TWN":"對不起……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나는 반드시 이번 임무를 성공시켜야만 해.","JPN":"でも、俺は必ず今回の任務を成功させないといけない。","ENG":"But I need to complete this mission no matter what.","TWN":"但我必須要讓這次任務成功。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 하기로…… 다짐했으니까.","JPN":"そうするって……決めたから。","ENG":"That's what... I promised.","TWN":"就是這樣……因為我已經下定決心了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……케흑!","JPN":"……うぐっ！","ENG":"...Kgh!","TWN":"……咳咳！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"날 원망하려면…… 원망해도 좋아.","JPN":"俺を恨みたければ……恨んでもいい。","ENG":"You can blame me all you want...","TWN":"如果你想怨我……那就怨吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까……!","JPN":"だから……！","ENG":"So...!","TWN":"所以……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아아, 아아아아아……!","JPN":"ああ、あああああ……！","ENG":"Aah, aaaaaaagh...!","TWN":"啊啊，啊啊啊啊啊……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까…… 여기서 널 죽여서라도 파편을 막겠어.","JPN":"だから……ここでお前を殺してでも破片を止める。","ENG":"So... I will kill you right here to stop the Fragment.","TWN":"所以……哪怕在這裡殺了你，我也要阻止碎片。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"내 이름과 명예를 걸고 너희에게 맹세하마.","JPN":"俺の名前と名誉をかけて、お前たちに誓おう。","ENG":"I swear on my name and honor.","TWN":"我以我的名字和榮譽向你們發誓。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L3_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 요원님……?","JPN":"バーネット様……？","ENG":"Agent Burnett...?","TWN":"伯內特先生……？"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"아무리 힘들어도, 아무리 오랜 시간이 걸려도 너희를 포기하지 않겠다.","JPN":"どんなに辛い思いをしても、どんなに長い時間がかかっても、俺はお前たちのことを諦めない。","ENG":"No matter how hard, no matter how long, I won't give up on you.","TWN":"無論多累，會花費多少時間，我也不會放棄你們。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 지금은.","JPN":"だから今は……","ENG":"So for now.","TWN":"所以現在……"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"지금은 조금만 우리를 믿고 기다려 줄 수 있겠니?","JPN":"今は俺たちを信じて、待ってくれないか。","ENG":"Could you trust us and wait a bit?","TWN":"可以相信我，再等我們一會兒嗎？"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"네. 기다릴게요.","JPN":"はい、待ちます。","ENG":"Okay. I'll wait.","TWN":"好的，我會等你的。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"다른 건 몰라도…… 저, 참는 건 자신 있거든요.","JPN":"なにより……私、耐えることなら自信あるんです。","ENG":"I don't know about anything else, but... I know I'm good at enduring.","TWN":"別的不說……我對忍耐是很有信心的。"},"stage":{"bg":"HALL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇…… 군요…….","JPN":"そう……ですか。","ENG":"I... see...","TWN":"原來……如此……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"당신이…… 당신은…… 버넷 요원님이로군요.","JPN":"あなたが……あなたは……バーネット様ですね。","ENG":"It's you... You're Agent Burnett.","TWN":"你是……你是……伯內特。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 소리야……? 너, 날 알아……!?","JPN":"何言ってるんだ……？　お前、俺のことを知ってるのか……！？","ENG":"What are you...? Do you know me...?!","TWN":"說什麼呢……？你，你認識我……？！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아아…… 다행이다.","JPN":"ああ……よかった。","ENG":"Ahh... I'm so relieved.","TWN":"啊……真是萬幸。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"정말로…… 정말로 이곳을 찾아 와주셨어.","JPN":"本当に……本当にここを探し出してくださった。","ENG":"You really... You really found me.","TWN":"你真的……真的找來這裡了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"늦지 않고…… 찾아와 주셨어.","JPN":"遅くなる前に……来てくださった。","ENG":"You... really made it before it was too late.","TWN":"你沒有來晚……真的來找我了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"다행이다……. 다행이다…….","JPN":"よかった……よかった……","ENG":"I'm so... relieved...","TWN":"太好了……真是太好了……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그게 무슨?","JPN":"どういうことだ？","ENG":"What?","TWN":"你在說什麼？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"저…… 줄곧 여기서 당신을 기다리고 있었어요.","JPN":"私……ここでずっとあなたを待っていました。","ENG":"I've... been waiting for you, all this time.","TWN":"我……一直在這裡等你。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"혼자서…… 아주…… 아주 오랜 시간을…… 견뎌왔어요.","JPN":"一人で……とても……とても長い時間を……耐えてきました。","ENG":"I endured a long... long time... alone.","TWN":"我一個人……撐過了……很久……很久的時間。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아무리 무섭고…… 고통스러워도…… 꾹 참았어요.","JPN":"どんなに怖くても……辛くても……我慢しました。","ENG":"Even though it was really scary... and painful... I endured it.","TWN":"再怎麼害怕……痛苦……我也忍住了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"왜냐하면…….","JPN":"なぜなら……","ENG":"Because...","TWN":"因為……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"저, 참는 것만큼은 자신있으니까.","JPN":"私、耐えることなら自信ありますので。","ENG":"If there's one thing I'm good at, it's enduring.","TWN":"我對忍耐是很有信心的。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그게…… 무슨 소리야?","JPN":"それは……どういうことだ？","ENG":"What... are you talking about?","TWN":"你在……說什麼？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대체 무슨 헛소리를 하는 거냐고!!","JPN":"いったい何を言ってるんだ！！","ENG":"What the hell are you talking about?!","TWN":"你到底在胡說八道什麼！！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대답해! 할아버지가 너한테 뭐라고 한 거야!","JPN":"答えろ！　お爺さんはお前になんて言ったんだ！","ENG":"Answer me! What did my grandfather say to you?!","TWN":"回答我！爺爺跟你說什麼了！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"넌 대체…… 얼마나 오랫동안 이런 곳에서…….","JPN":"お前はいったい……どれだけの時間をこんなとこで……","ENG":"How long... have you been in a place like...","TWN":"你到底……在這種地方待了多久……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"당신은…… 버넷.","JPN":"あなたは……バーネット。","ENG":"You're... Burnett.","TWN":"你是……伯內特。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"이 고통에서 절 구원해줄…… 유일한 사람.","JPN":"この苦しみから私を救ってくれる……唯一の人。","ENG":"The only person... who would save me from this pain.","TWN":"是可以把我從這個痛苦中解救出來的……唯一的人。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그러니까…… 여기서 절 끝내 주세요.","JPN":"ですから……ここで私を終わらせてください。","ENG":"So... please end me here.","TWN":"所以……請在這裡了結我吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그게…… 모두가 행복해질 수 있는…… 유일한 결말이니까요.","JPN":"それが……皆が幸せになれる……唯一の方法ですから。","ENG":"That's... the only way... everyone can be happy.","TWN":"因為那是……能讓所有人都能變得幸福的……唯一結局。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 할아버지는 정말로 널…….","JPN":"じゃあ、お爺さんは本当にお前を……","ENG":"Then, did my grandfather really try to–","TWN":"那麼，爺爺真的把你……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"제 안에…… 파편은…… 제가 죽는 그 순간까지…… 붙잡고 있을게요.","JPN":"私の中の……破片は……私が死ぬ瞬間まで……捉まえておきます。","ENG":"I'll hold... the Fragment inside me... until the moment I die.","TWN":"我身體裡的……那塊碎片……我會牢牢抓住……直到我死的那一刻。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 요원님이 다치지 않게…… 놓지 않을 게요.","JPN":"バーネット様が怪我しないように……放しません。","ENG":"I won't let go... so that you don't get hurt.","TWN":"我不會放手……不會讓伯內特先生受傷的。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"절대로…… 날 뛰게 두지 않을 테니까……!","JPN":"絶対に……暴れさせたりしませんから……！","ENG":"I won't... let it go berserk...!","TWN":"我絕對……不會讓碎片暴走的……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"자, 어서……!","JPN":"さあ、早く……！","ENG":"Now, please...!","TWN":"所以，快點……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"젠장, 젠장, 젠장, 젠장할……!!","JPN":"くそ、くそ、くそ……！！","ENG":"Damn it, damn it, damn it, damn it...!!","TWN":"該死，該死，該死，該死……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"넌 억울하지도 않아!?","JPN":"お前は悔しくないのか！？","ENG":"Aren't you upset?!","TWN":"你都不覺得冤枉嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 곳에 버려져, 그런 꼴이 될때까지……!","JPN":"こんな場所に放り出されて、そんな姿になるまで……！","ENG":"You were abandoned in a place like this, and you've been...!","TWN":"被丟到這種地方，直到變成那副摸樣……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"17년이나 망할 할배를 기다려 왔다는 거잖아! 올지도 안 올지도 모르는 사람을!","JPN":"17年もくそジジイを待ってたってことじゃないか！　来ないかもしれない人間を！","ENG":"You've been waiting for that old man for 17 years! Someone who you didn't know would show up or not!","TWN":"那個該死的老頭，你等了他17年！你都不確定他到底會不會來！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하고 싶은 것도…… 먹고 싶은 것도 있었을 텐데……!","JPN":"やりたいことも……食べたいものもあったはずなのに……！","ENG":"You must've had things you wanted to do... things you wanted to eat...!","TWN":"你肯定也有想做的事……想吃的東西吧……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 요원님……?","JPN":"バーネット様……？","ENG":"Agent Burnett...?","TWN":"伯內特先生……？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"근데 뭐? 죽여달라고? 그게 모두가 행복해질 수 있는 결말이라고?","JPN":"それなのに、何だ？　殺してくれだと？　それが皆が幸せになる唯一の方法だと？","ENG":"And what? You want me to kill you? That's the only way everyone can be happy?","TWN":"但是什麼？讓我殺了你？那是所有人都能幸福的結局？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"웃기지 마! 웃기지 말라고!","JPN":"ざけんな！　ふざけんなよ！","ENG":"That's nonsense! Absolute nonsense!","TWN":"笑死人了！開什麼玩笑！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"꼬맹이면, 꼬맹이답게 그냥 얌전하게 살려달라고 빌란 말이야!!","JPN":"ガキならガキらしく、大人しく助けてくださいって言えよ！！","ENG":"You're a kid, so just beg for your life like the little kid you are!!","TWN":"你就該有個小孩子的樣子，求我讓你活下去！！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"지금…… 뭐하시는 거예요……?","JPN":"今……何をしてるんですか……？","ENG":"What... are you doing...?","TWN":"你在……做什麼……？"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"보면 몰라? 네 몸에 뒤얽힌 파편들을 뜯어내고 있잖아!","JPN":"見て分かんないのか？　お前の体に絡みついてる破片をはぎ取ってるだろ！","ENG":"What does it look like? I'm ripping away the Fragments twisted around your body!","TWN":"你看不出來嗎？我在清理你身上的碎片！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"널 거기서 끄집어 낼 거야.","JPN":"お前をそこから引き出す。","ENG":"I'll get you out of there.","TWN":"我要把你從那里弄出來。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"무슨……!?","JPN":"何を……！？","ENG":"What...?!","TWN":"什麼……？！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"소용없어요. 저로부터 자라난 파편은 이제 제거할 수 없다고요.","JPN":"無理です。私から生えて来た破片はもう取り除けません。","ENG":"There's no use. The Fragment that grew out from me can't be removed anymore.","TWN":"沒用的。從我的身體裡長出來的碎片已經無法清除了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"うるせえ！","ENG":"Shut up!","TWN":"吵死了！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너처럼 파편과 연결되고도, 파편과 친구처럼 지내는 녀석을 알고 있어.","JPN":"お前みたいに破片と繋がっても、破片と友だちみたいになってる人間を知ってる。","ENG":"I know a girl who is connected to a Fragment but is friends with it.","TWN":"我認識一個像你這樣和碎片連在一起，卻還能和碎片和平相處的人。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 녀석에게 조언을 구해보자.","JPN":"あいつに助言を求める。","ENG":"Let's ask her for advice.","TWN":"跟那個傢伙請教一下吧。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"네……?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그게 아니라면, 기관으로 가자. 홍차 폭탄이라면 어떻게든 해줄거야.","JPN":"それが嫌なら、機関に行こう。紅茶爆弾ならなんとかしてくれるはずだ。","ENG":"If not, we can go to the Institute. Tea Bomb will do something.","TWN":"要不然，去機關吧。紅茶炸彈無論如何都會想辦法的。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"왕 싸가지이긴 해도, 이런 걸 보고 외면할 정도로 모진 녀석은 아니니까.","JPN":"性格は悪いけど、これを見て見捨てるような性悪じゃない。","ENG":"She can be a haughty jerk, but she's not mean enough to ignore this.","TWN":"雖然很沒教養，但她也不是個冷酷到見死不救的傢伙。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내가 부탁하면…… 어떻게든 해줄 거야.","JPN":"俺が頼めば……きっとなんとかしてくれる。","ENG":"If I ask her... she'll do something.","TWN":"我去求她……她無論如何都會答應的。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"What do you...?","TWN":"你在說什麼……？"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 잘 아는 회사 사장님도 있어.","JPN":"ああそうだ、知り合いの社長もいる。","ENG":"Yes, and there's a CEO of a company I'm close with.","TWN":"沒錯，還有和我比較熟悉的老闆。"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"별난 사람이긴 하지만 인맥도 넓고, 재주도 많은 사람이니까 어떻게든 도와줄 거야.","JPN":"ちょっと変わった人だけど顔も広いし、有能な人だから何とかして力を貸してくれるはずだ。","ENG":"He's odd, but he has connections and a lot of tricks up his sleeves. He'll be able to help.","TWN":"雖然是個怪人，但人脈廣，本事多，所以無論如何都能幫你的。"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"잠깐…… 잠깐만요……!","JPN":"ちょっと……待ってください……！","ENG":"Wait... Wait...!","TWN":"等一……等一下……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금까지 줄곧 참아왔다면서? 그럼 조금만 더 이 악물고 버텨.","JPN":"今まで耐えてきたんだろ？　じゃあもう少しだけ歯食いしばって耐えろよ。","ENG":"You've endured all this time, right? So endure just a little bit longer.","TWN":"你不是一直忍到了現在嗎？那你就再咬緊牙關多堅持一會兒吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"살아만 있다면…….","JPN":"生きてさえいれば……","ENG":"As long as you're alive...","TWN":"只要你活著……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"살아만 있다면, 원래대로 돌아 갈 방법은 다 같이 머리를 맞대고 고민하면 돼.","JPN":"生きてさえいれば、元に戻る方法なんかみんなで考えればいい。","ENG":"As long as you're alive, we can all put our heads together and think of a way to go back.","TWN":"只要你活著，大家就可以一起想辦法讓你回到原來的樣子。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 할배가 널 어쩔 작정이었는지…… 나는 몰라.","JPN":"俺の爺さんがお前をどうするつもりだったのか……俺にはわからない。","ENG":"I... don't know what my grandfather was going to do with you.","TWN":"我不知道……爺爺到底想拿你怎麼樣。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"けど……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 어쩔 수 없다는 핑계로 누군가를 희생시키는 꼴은 보고 싶지 않다고.","JPN":"けど、どうしようもないって理由で誰かを犠牲にするのは見たくないんだ。","ENG":"But I don't want to sacrifice anyone while saying there's no other choice.","TWN":"但是我不想看到那副以無可奈何為藉口而犧牲他人樣子。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아무 잘못도 없는 꼬맹이를 죽여서 얻을 수 있는 행복이라면…… ","JPN":"何の罪もないガキを殺して得られる幸せなんか…… ","ENG":"If it's a happiness that can only be earned through killing an innocent child...","TWN":"如果是要犧牲沒有任何過錯的孩子才能獲得的幸福……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나는 필요 없어!","JPN":"俺は要らない！","ENG":"I don't need it!","TWN":"那我不需要！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 내가 필요 없게 만들겠어!","JPN":"いや、要らないようにしてやる！","ENG":"No, I'll make it so that it's not needed!","TWN":"不，我會讓它變得沒有必要！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 일어나.","JPN":"だから立て。","ENG":"So get up.","TWN":"所以，快點起來啊。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"일어나서, 널 속박하고 있는 파편을 스스로 끊고 걸어 나와.","JPN":"立ち上がって、お前を束縛してる破片を自分の手で断ち切って歩いて出て来いよ。","ENG":"Get up, break the Fragments that are holding you down, and walk out.","TWN":"起來，掙脫束縛你的碎片，然後走出來。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……버넷 요원님.","JPN":"……バーネット様。","ENG":"...Agent Burnett.","TWN":"……伯內特先生。"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내가…… 도와줄 테니까!","JPN":"俺が……助けてやるから！","ENG":"I'll... help you!","TWN":"我會……幫你！"},"stage":{"bg":"SS_ESPR_06","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_02"},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"후후, 이상적인 이야기로군.","JPN":"ふふ、理想論だな。","ENG":"Haha, how idealistic.","TWN":"呵呵，真是一個理想的故事。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"너무나 순진무구한 이상이라서, 오히려 마음에 들 정도야.","JPN":"純真無垢な理想すぎて、逆に気に入った。","ENG":"It is so idealistic that I almost like it.","TWN":"你的天真無邪超出了我的想像，反而讓我很滿意。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너는……?","JPN":"お前は……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"커헉……!!","JPN":"くはっ……！！","ENG":"Kuh...!!","TWN":"咳呃……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만 이상이 아무리 숭고할지언정, 힘이 없다면 무엇하나 이룰 수 없지.","JPN":"だが、どんなに崇高な理想であれ、力がなければ何一つ成し遂げることはできない。","ENG":"But regardless of how noble your ideals are, you cannot achieve anything without power.","TWN":"但無論理想有多崇高，如果沒有與之相配的力量，也無法成就任何事情。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네 놈은 어떨까?","JPN":"貴様はどうかな。","ENG":"How about you?","TWN":"你又是怎麼想的？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네 놈이 함부로 지껄여 댄 이상을, 네 놈이 지켜낼 수 있을까?","JPN":"貴様が語った理想を、貴様は守り切れるか？","ENG":"Will you be able to protect the ideal that you so boldly proclaimed?","TWN":"你能守護你口中侃侃而談的理想嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너…… 너어……!","JPN":"お、お前……！","ENG":"You... Youuu...!","TWN":"你……你……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"커흑, 무슨 짓을 하려는 거야……!!","JPN":"くうっ、何をするつもりだ……！！","ENG":"Kgh, what are you trying to do...?!","TWN":"咳咳，你想幹什麼……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"무슨 짓을 할 거냐고?","JPN":"何をするつもりかって？","ENG":"What am I trying to do?","TWN":"想幹什麼？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"의식을 치를 거다. 어머니를 위한 의식을.","JPN":"儀式を行なう。お母さんのための儀式をな。","ENG":"I am about to perform the ritual. The ritual for Mother.","TWN":"當然是為母親，舉行儀式了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"의식이라고?","JPN":"儀式？","ENG":"Ritual?","TWN":"儀式？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"다, 당신은……?","JPN":"あ、あなたは……？","ENG":"Y-you're...?","TWN":"你，你是……？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이게 제임스가 말했던 성배인가?","JPN":"これがジェームスの言っていた聖杯か？","ENG":"Is this the Holy Grail James mentioned?","TWN":"這就是詹姆斯說的聖杯嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"훌륭하군. 이 정도라면 어머니를 담을 그릇으로는 손색이 없겠어.","JPN":"素晴らしい。お母さんを宿す器としては非の打ちどころがない。","ENG":"Excellent. This should be good enough as a vessel for Mother.","TWN":"好極了。這種程度，作為母親的器皿也毫不遜色。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지마……!!","JPN":"やめろ……！！","ENG":"Stop...!!","TWN":"停下……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지 말라고!! 이 개자식아……!!","JPN":"やめろ！！　このくそ野郎……！！","ENG":"Stop it!! You bastard...!!","TWN":"我叫你停下！！你這個混蛋……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"모든 것은, 지식의 호수가 하나 되기 위해서.","JPN":"すべては、知識の湖が一つになるため。","ENG":"Everything... is for the Lake of Knowledge to become one.","TWN":"一切都是為了讓知識湖水合而為一。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_HATE"},"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ONLY_FIERCE_ESPR_KNIGHT_SKILL_2"}]`);export{e as default};